stopwords = set(['this','facility','establishment','offers','a','range','of','services','service','the','and','in','category','categories','products','provides','offering','offers','providing'])

def extract_categories(desc):
    if not isinstance(desc, str):
        return []
    low = desc.lower()
    token = None
    keys = ['category of', 'in the category of', 'offers a range of', 'offers a range', 'offers a', 'offers']
    for key in keys:
        if key in low:
            idx = low.find(key)
            token = desc[idx+len(key):]
            break
    if token is None:
        if ' this ' in low:
            idx = low.find(' this ')
            token = desc[idx+6:]
        else:
            token = desc
    token = token.split('.')[0]
    if token.lower().startswith('located at'):
        parts = token.split(' in ', 1)
        if len(parts) == 2:
            token = parts[1]
    token_norm = token.replace('&', ',').replace('/', ',').replace(';', ',')
    token_norm = token_norm.replace(' and ', ',')
    raw_parts = [p.strip() for p in token_norm.split(',') if p.strip()]
    parts_clean = []
    for p in raw_parts:
        p2 = p.strip(" '")
        p2 = p2.strip('"')
        if not p2:
            continue
        words = [w for w in p2.split() if w.lower() not in stopwords]
        if not words:
            continue
        newp = ' '.join(words).strip(' ,')
        if len(newp) > 1:
            parts_clean.append(newp)
    return parts_clean

